/** Minimal PCM WAV (mono int16 LE) for piping to multimon / ffmpeg / STT experiments. */

export function writeWavPcm16MonoLe(
  pcm: Int16Array,
  sampleRateHz: number,
): Uint8Array {
  const dataBytes = pcm.length * 2;
  const buf = new ArrayBuffer(44 + dataBytes);
  const dv = new DataView(buf);
  const u8 = new Uint8Array(buf);
  const writeStr = (off: number, s: string): void => {
    for (let i = 0; i < s.length; i++) {
      dv.setUint8(off + i, s.charCodeAt(i)!);
    }
  };
  writeStr(0, 'RIFF');
  dv.setUint32(4, 36 + dataBytes, true);
  writeStr(8, 'WAVE');
  writeStr(12, 'fmt ');
  dv.setUint32(16, 16, true);
  dv.setUint16(20, 1, true);
  dv.setUint16(22, 1, true);
  dv.setUint32(24, sampleRateHz, true);
  dv.setUint32(28, sampleRateHz * 2, true);
  dv.setUint16(32, 2, true);
  dv.setUint16(34, 16, true);
  writeStr(36, 'data');
  dv.setUint32(40, dataBytes, true);
  let o = 44;
  for (let i = 0; i < pcm.length; i++) {
    dv.setInt16(o, pcm[i]!, true);
    o += 2;
  }
  return u8;
}
